class Solution:
    def minChanges(self, n: int, k: int) -> int:
        xor = n ^ k
        # Count the number of 1s in the XOR result
        count_ones = bin(xor).count('1')

        # If there are any bits set in k that are not set in n, it's impossible
        if (k & ~n) != 0:
            return -1

        return count_ones
